const l=async(i,o)=>{try{const n=o.filter(e=>e.faceEnrolled&&e.faceData&&e.faceData.startsWith("data:image"));if(n.length===0)return console.error("[Biometric] Prediction aborted: No enrolled users found in gallery."),null;console.log(`[Biometric] Requesting backend matching against ${n.length} enrolled signatures...`);const r=await fetch("https://newapp-p81d.onrender.com/api/biometric/predict",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({capturedDataUrl:i,gallery:n.map(e=>({id:e.id,faceData:e.faceData}))})});if(!r.ok){const e=await r.json().catch(()=>({}));throw new Error(e.error||`Server error: ${r.statusText}`)}const t=await r.json();if(console.log(`[Biometric] Raw Match Result: ID=${t.id}, Confidence=${t.confidence}, Reason=${t.reason||"N/A"}`),t.id&&t.id!=="none"&&t.id!=="low_confidence"){let e=t.id;return typeof e=="string"&&e.startsWith("USER_ID_")&&(e=e.replace("USER_ID_","")),o.find(a=>a.id===String(e))||null}return t.id==="low_confidence"&&console.warn("[Biometric] Match rejected due to low confidence:",t.confidence),null}catch(n){return console.error("Biometric Prediction Error (Backend Link):",n),null}};export{l as predictEmployeeIdentity};
